#include <stdio.h>
bool searchInRotatedSortedArrayII(int* arr, int arrSize, int k) {
    for (int i = 0; i < arrSize; i++) {
        if (arr[i] == k) return true;
    }
    return false;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;
class Solution {
public:
    bool searchInARotatedSortedArrayII(vector<int>& arr, int k) {
        int n = arr.size();
        for (int i = 0; i < n; i++) {
            if (arr[i] == k) return true;
        }
        return false;
    }
};

